import{_ as e,o as a,c as t,Q as r}from"./chunks/framework.1b6086f5.js";const k=JSON.parse('{"title":"多阶段构建","description":"","frontmatter":{},"headers":[],"relativePath":"doc/DevOps/Docker/实战/多阶段构建.md","filePath":"packages/doc/src/DevOps/Docker/实战/多阶段构建.md","lastUpdated":1703174217000}'),o={name:"doc/DevOps/Docker/实战/多阶段构建.md"},c=r('<h1 id="多阶段构建" tabindex="-1">多阶段构建 <a class="header-anchor" href="#多阶段构建" aria-label="Permalink to &quot;多阶段构建&quot;">​</a></h1><ul><li><a href="https://zhuanlan.zhihu.com/p/612292168" target="_blank" rel="noreferrer">参考</a></li><li></li></ul><p>Dockerfile 多阶段构建是一种优化 Docker 镜像构建的方法，它可以减少 Docker 镜像的大小和运行时的资源消耗。</p><h1 id="多阶段构建的基本概念" tabindex="-1">多阶段构建的基本概念 <a class="header-anchor" href="#多阶段构建的基本概念" aria-label="Permalink to &quot;多阶段构建的基本概念&quot;">​</a></h1><p>Dockerfile 多阶段构建的基本思路是利用多个阶段构建镜像，每个阶段都有一个基础镜像，并在这个基础镜像上进行构建。</p><p>在每个阶段的最后，通过 COPY 或者 FROM 语句将需要的文件或者库复制到最终的镜像中。</p><p>这种方法可以减少最终镜像的大小，同时也可以避免在运行时不必要的资源消耗。</p>',7),_=[c];function s(l,i,n,p,d,h){return a(),t("div",null,_)}const u=e(o,[["render",s]]);export{k as __pageData,u as default};
